import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { Helmet } from 'react-helmet-async';
import toast from 'react-hot-toast';
import { useCart } from '../context/CartContext';
import ProductCard from '../components/ProductCard';
import { unwrapFeaturedResponse, unwrapCategoriesResponse, apiMessage } from '../lib/api';

/** Emoji icon by category slug (API-driven names; slug is stable). */
function iconForCategorySlug(slug) {
  const s = String(slug || '').toLowerCase();
  if (s.includes('electronic')) return '📱';
  if (s.includes('fashion')) return '👗';
  if (s.includes('home')) return '🏡';
  if (s.includes('beaut')) return '💄';
  if (s.includes('sport')) return '⚽';
  if (s.includes('book')) return '📚';
  if (s.includes('toy')) return '🧸';
  return '🛍️';
}

const HOME_CATEGORY_LIMIT = 5;

const Home = () => {
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const [featuredLoading, setFeaturedLoading] = useState(true);
  const [featuredError, setFeaturedError] = useState(null);
  const [categories, setCategories] = useState([]);
  const [categoriesLoading, setCategoriesLoading] = useState(true);
  const [categoriesError, setCategoriesError] = useState(null);
  const { addToCart } = useCart();

  useEffect(() => {
    fetchFeaturedProducts();
  }, []);

  useEffect(() => {
    let cancelled = false;
    async function loadCategories() {
      setCategoriesLoading(true);
      setCategoriesError(null);
      try {
        const res = await axios.get('/api/categories');
        const list = unwrapCategoriesResponse(res);
        if (!cancelled) setCategories(list.slice(0, HOME_CATEGORY_LIMIT));
      } catch (error) {
        console.error('Categories fetch error:', error);
        if (!cancelled) {
          setCategoriesError(apiMessage(error, 'Failed to load categories'));
          setCategories([]);
        }
      } finally {
        if (!cancelled) setCategoriesLoading(false);
      }
    }
    loadCategories();
    return () => {
      cancelled = true;
    };
  }, []);

  const fetchFeaturedProducts = async () => {
    setFeaturedLoading(true);
    setFeaturedError(null);
    try {
      const response = await axios.get('/api/products/featured');
      const list = unwrapFeaturedResponse(response);
      setFeaturedProducts(list.slice(0, 4));
    } catch (error) {
      console.error('Error fetching products:', error);
      const msg =
        error.code === 'ERR_NETWORK' || error.message?.includes('Network Error')
          ? 'Cannot reach the API. Start the backend (port 5000) — from the project folder run npm run dev, or cd backend && npm start.'
          : apiMessage(error, 'Failed to load products');
      setFeaturedError(msg);
      setFeaturedProducts([]);
    } finally {
      setFeaturedLoading(false);
    }
  };

  const handleAddToCart = async (product) => {
    await addToCart(product, 1);
  };

  return (
    <>
      <Helmet>
        <title>Nova Shop — Premium style & living</title>
        <meta
          name="description"
          content="Nova Shop — curated products across electronics, fashion, home, beauty and sports."
        />
      </Helmet>

      {/* Hero — split: copy + lifestyle image (Nova Shop) */}
      <section className="hero hero--home" aria-label="Hero banner">
        <div className="hero__copy">
          <div className="hero__copy-inner container">
            <p className="hero-badge">New season collection</p>
            <h1 className="hero-title">
              Discover <em>Premium</em> Style &amp; Living
            </h1>
            <p className="hero-lead">
              Curated collections of the world&apos;s finest products — delivered to your door with
              next-day shipping.
            </p>
            <div className="hero-actions">
              <Link to="/shop" className="btn btn-primary btn-hero-primary">
                Shop now →
              </Link>
              <a href="#featured" className="btn btn-outline btn-hero-outline">
                View collections
              </a>
            </div>
            <div className="hero-stats" role="group" aria-label="Store highlights">
              <div className="hero-stat">
                <span className="hero-stat__value">10K+</span>
                <span className="hero-stat__label">Products</span>
              </div>
              <span className="hero-stats__divider" aria-hidden="true" />
              <div className="hero-stat">
                <span className="hero-stat__value">50K+</span>
                <span className="hero-stat__label">Customers</span>
              </div>
              <span className="hero-stats__divider" aria-hidden="true" />
              <div className="hero-stat">
                <span className="hero-stat__value">4.9★</span>
                <span className="hero-stat__label">Rating</span>
              </div>
            </div>
          </div>
        </div>
        <div className="hero__media">
          <img
            className="hero__media-img"
            src="https://images.unsplash.com/photo-1556228578-0d85b1a4d571?w=1400&auto=format&fit=crop&q=82"
            alt=""
            width={1400}
            height={933}
            decoding="async"
            fetchPriority="high"
          />
          <div className="hero__media-scrim" aria-hidden="true" />
        </div>
      </section>

      <section className="section bg-cream" id="categories" aria-label="Shop categories">
        <div className="container">
          <div className="section-header text-center">
            <span className="section-tag">Browse by Category</span>
            <h2>What Are You Looking For?</h2>
          </div>
          <div className="categories-grid">
            <Link to="/category/electronics" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">📱</span>
              <span>Electronics</span>
            </Link>
            <Link to="/category/fashion" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">👗</span>
              <span>Fashion</span>
            </Link>
            <Link to="/category/home" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">🏡</span>
              <span>Home</span>
            </Link>
            <Link to="/category/beauty" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">💄</span>
              <span>Beauty</span>
            </Link>
            <Link to="/category/sports" className="category-chip category-chip--vertical">
              <span className="category-chip__icon">⚽</span>
              <span>Sports</span>
            </Link>
          </div>
        </div>
      </section>

      <section className="section" id="featured" aria-label="Featured products">
        <div className="container">
          <div className="section-header section-header-flex">
            <div>
              <span className="section-tag">Handpicked for You</span>
              <h2>Featured Products</h2>
            </div>
            <Link to="/shop" className="btn btn-outline btn-sm">
              View All ›
            </Link>
          </div>
          {featuredLoading ? (
            <div className="products-grid">
              {[1, 2, 3, 4].map((i) => (
                <ProductCard key={i} loading />
              ))}
            </div>
          ) : featuredError ? (
            <div className="api-error-banner" role="alert">
              <p>
                <strong>Featured products could not be loaded.</strong> {featuredError}
              </p>
              <button type="button" className="btn btn-outline btn-sm" onClick={fetchFeaturedProducts}>
                Retry
              </button>
            </div>
          ) : featuredProducts.length === 0 ? (
            <p className="empty-products-hint empty-products-hint--muted" style={{ textAlign: 'center' }}>
              No products yet. Restart the backend to auto-seed demos, or run{' '}
              <code>node scripts/seedDatabase.js</code> in <code>backend</code>, then refresh.
            </p>
          ) : (
            <div className="products-grid">
              {featuredProducts.map((product) => (
                <ProductCard key={product._id} product={product} onAddToCart={handleAddToCart} />
              ))}
            </div>
          )}
        </div>
      </section>

      <section className="promo-banner" aria-label="Promotional offer">
        <div className="container promo-content">
          <span className="section-tag section-tag-gold">Limited Time</span>
          <h2>Get 20% Off Your First Order</h2>
          <p>Use the code below at checkout. Valid for new customers only.</p>
          <div className="promo-code">
            <span>NOVA20</span>
            <button
              type="button"
              className="copy-btn"
              onClick={() => {
                navigator.clipboard.writeText('NOVA20');
                toast.success('Code copied to clipboard!');
              }}
            >
              Copy
            </button>
          </div>
          <Link to="/shop" className="btn btn-gold">
            Shop the Sale ›
          </Link>
        </div>
      </section>

      <section className="section bg-cream" aria-label="Why choose us">
        <div className="container">
          <div className="section-header text-center">
            <span className="section-tag">Why Nova Shop</span>
            <h2>Shopping Made Simple</h2>
          </div>
          <div className="trust-grid">
            <div className="trust-card">
              <div className="trust-card__icon">🚚</div>
              <h4>Free Delivery</h4>
              <p>On orders over £50. Next-day available.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">🔒</div>
              <h4>Secure Payments</h4>
              <p>SSL encrypted. Pay with card, PayPal & more.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">↩️</div>
              <h4>Easy Returns</h4>
              <p>30-day hassle-free returns policy.</p>
            </div>
            <div className="trust-card">
              <div className="trust-card__icon">💬</div>
              <h4>24/7 Support</h4>
              <p>Live chat, email or phone — always here.</p>
            </div>
          </div>
        </div>
      </section>
    </>
  );
};

export default Home;
